mapper.update:
update positions_51
set position_name = #{positionName},
    hierarchy_level = #{hierarchyLevel},
    weight_base = #{weightBase},
    version = #{version} + 1,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where position_id = #{positionId}
  and version = #{version}
  and is_deleted = 'n'

update positions_51
set is_deleted = 'y',
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where position_id = #{positionId}
